// --- SAMLResponseParser ---
class SAMLResponseParser {

    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";

    public SAMLResponse parse(String samlXml) throws SAMLException {
        if (samlXml == null || samlXml.trim().isEmpty()) {
            throw new SAMLException("SAML response XML is null or empty");
        }

        Document document = parseXmlDocument(samlXml);
        Element root = document.getDocumentElement();

        validateResponseElement(root);

        SAMLResponse response = new SAMLResponse();
        extractResponseAttributes(root, response);
        extractIssuer(root, response);
        extractStatus(root, response);
        extractAssertions(root, response);

        return response;
    }

    public SAMLResponse parseBase64(String base64Response) throws SAMLException {
        if (base64Response == null || base64Response.trim().isEmpty()) {
            throw new SAMLException("Base64 SAML response is null or empty");
        }
        try {
            byte[] decoded = Base64.getDecoder().decode(base64Response.trim());
            String xml = new String(decoded, StandardCharsets.UTF_8);
            return parse(xml);
        } catch (IllegalArgumentException e) {
            throw new SAMLException("Invalid Base64 encoding in SAML response", e);
        }
    }

    private Document parseXmlDocument(String xml) throws SAMLException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            // Security: disable external entities to prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xml));
            return builder.parse(inputSource);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new SAMLException("Failed to parse SAML XML document: " + e.getMessage(), e);
        }
    }

    private void validateResponseElement(Element root) throws SAMLException {
        String localName = root.getLocalName();
        String namespaceURI = root.getNamespaceURI();

        if (!"Response".equals(localName)) {
            throw new SAMLException("Root element must be 'Response', but found: " + localName);
        }

        if (!SAML2_PROTOCOL_NS.equals(namespaceURI)) {
            throw new SAMLException("Response element namespace must be '" + SAML2_PROTOCOL_NS +
                    "', but found: " + namespaceURI);
        }

        String version = root.getAttribute("Version");
        if (!"2.0".equals(version)) {
            throw new SAMLException("SAML version must be '2.0', but found: " + version);
        }

        String id = root.getAttribute("ID");
        if (id == null || id.trim().isEmpty()) {
            throw new SAMLException("Response element must have an 'ID' attribute");
        }

        String issueInstant = root.getAttribute("IssueInstant");
        if (issueInstant == null || issueInstant.trim().isEmpty()) {
            throw new SAMLException("Response element must have an 'IssueInstant' attribute");
        }
    }

    private void extractResponseAttributes(Element root, SAMLResponse response) throws SAMLException {
        response.setResponseId(root.getAttribute("ID"));
        response.setInResponseTo(getAttributeOrNull(root, "InResponseTo"));
        response.setDestination(getAttributeOrNull(root, "Destination"));

        String issueInstantStr = root.getAttribute("IssueInstant");
        try {
            response.setIssueInstant(Instant.parse(issueInstantStr));
        } catch (DateTimeParseException e) {
            throw new SAMLException("Invalid IssueInstant format: " + issueInstantStr, e);
        }
    }

    private void extractIssuer(Element parent, SAMLResponse response) {
        NodeList issuerNodes = parent.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            Element issuerElement = (Element) issuerNodes.item(0);
            // Only use the Issuer that is a direct child of the Response
            if (issuerElement.getParentNode().equals(parent)) {
                response.setIssuer(issuerElement.getTextContent().trim());
            }
        }
    }

    private void extractStatus(Element root, SAMLResponse response) throws SAMLException {
        NodeList statusNodes = root.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Status");
        if (statusNodes.getLength() == 0) {
            throw new SAMLException("Response must contain a Status element");
        }

        Element statusElement = (Element) statusNodes.item(0);

        NodeList statusCodeNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() == 0) {
            throw new SAMLException("Status must contain a StatusCode element");
        }

        Element statusCodeElement = (Element) statusCodeNodes.item(0);
        response.setStatusCode(statusCodeElement.getAttribute("Value"));

        NodeList statusMessageNodes = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusMessage");
        if (statusMessageNodes.getLength() > 0) {
            response.setStatusMessage(statusMessageNodes.item(0).getTextContent().trim());
        }
    }

    private void extractAssertions(Element root, SAMLResponse response) throws SAMLException {
        NodeList assertionNodes = root.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");

        for (int i = 0; i < assertionNodes.getLength(); i++) {
            Element assertionElement = (Element) assertionNodes.item(i);
            SAMLAssertion assertion = parseAssertion(assertionElement);
            response.addAssertion(assertion);
        }
    }

    private SAMLAssertion parseAssertion(Element assertionElement) throws SAMLException {
        SAMLAssertion assertion = new SAMLAssertion();

        assertion.setAssertionId(assertionElement.getAttribute("ID"));

        // Issuer
        NodeList issuerNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            assertion.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Subject
        parseSubject(assertionElement, assertion);

        // Conditions
        parseConditions(assertionElement, assertion);

        // AuthnStatement
        parseAuthnStatement(assertionElement, assertion);

        // AttributeStatement
        parseAttributeStatement(assertionElement, assertion);

        return assertion;
    }

    private void parseSubject(Element assertionElement, SAMLAssertion assertion) {
        NodeList subjectNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() > 0) {
            Element subjectElement = (Element) subjectNodes.item(0);
            NodeList nameIdNodes = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
            if (nameIdNodes.getLength() > 0) {
                Element nameIdElement = (Element) nameIdNodes.item(0);
                assertion.setSubject(nameIdElement.getTextContent().trim());
                assertion.setSubjectNameFormat(getAttributeOrNull(nameIdElement, "Format"));
            }
        }
    }

    private void parseConditions(Element assertionElement, SAMLAssertion assertion) throws SAMLException {
        NodeList conditionsNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditionsElement = (Element) conditionsNodes.item(0);

            String notBefore = getAttributeOrNull(conditionsElement, "NotBefore");
            if (notBefore != null) {
                try {
                    assertion.setNotBefore(Instant.parse(notBefore));
                } catch (DateTimeParseException e) {
                    throw new SAMLException("Invalid NotBefore format: " + notBefore, e);
                }
            }

            String notOnOrAfter = getAttributeOrNull(conditionsElement, "NotOnOrAfter");
            if (notOnOrAfter != null) {
                try {
                    assertion.setNotOnOrAfter(Instant.parse(notOnOrAfter));
                } catch (DateTimeParseException e) {
                    throw new SAMLException("Invalid NotOnOrAfter format: " + notOnOrAfter, e);
                }
            }

            NodeList audienceNodes = conditionsElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
            for (int i = 0; i < audienceNodes.getLength(); i++) {
                assertion.addAudienceRestriction(audienceNodes.item(i).getTextContent().trim());
            }
        }
    }

    private void parseAuthnStatement(Element assertionElement, SAMLAssertion assertion) throws SAMLException {
        NodeList authnStatementNodes = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatementElement = (Element) authnStatementNodes.item(0);

            String authnInstant = getAttributeOrNull(authnStatementElement, "AuthnInstant");
            if (authnInstant != null) {
                try {
                    assertion.setAuthnInstant(Instant.parse(authnInstant));
                } catch (DateTimeParseException e) {
                    throw new SAMLException("Invalid AuthnInstant format: " + authnInstant, e);
                }
            }

            assertion.setSessionIndex(getAttributeOrNull(authnStatementElement, "SessionIndex"));

            NodeList authnContextClassRefNodes = authnStatementElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "AuthnContextClassRef");
            if (authnContextClassRefNodes.getLength() > 0) {
                assertion.setAuthnContextClassRef(authnContextClassRefNodes.item(0).getTextContent().trim());
            }
        }
    }

    private void parseAttributeStatement(Element assertionElement, SAMLAssertion assertion) {
        NodeList attrStatementNodes = assertionElement.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "AttributeStatement");
        if (attrStatementNodes.getLength() > 0) {
            Element attrStatementElement = (Element) attrStatementNodes.item(0);
            NodeList attributeNodes = attrStatementElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "Attribute");

            for (int i = 0; i < attributeNodes.getLength(); i++) {
                Element attrElement = (Element) attributeNodes.item(i);
                String name = attrElement.getAttribute("Name");
                String nameFormat = getAttributeOrNull(attrElement, "NameFormat");

                List<String> values = new ArrayList<>();
                NodeList valueNodes = attrElement.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "AttributeValue");
                for (int j = 0; j < valueNodes.getLength(); j++) {
                    values.add(valueNodes.item(j).getTextContent().trim());
                }

                SAMLAttribute attribute = new SAMLAttribute(name, nameFormat, values);
                assertion.addAttribute(attribute);
            }
        }
    }

    private String getAttributeOrNull(Element element, String attrName) {
        String value = element.getAttribute(attrName);
        return (value != null && !value.trim().isEmpty()) ? value.trim() : null;
    }
}

// --- AuthenticatedSession ---
class AuthenticatedSession {
    private final String sessionId;
    private final String userId;
    private final String issuer;
    private final Map<String, List<String>> userAttributes;
    private final Instant createdAt;
    private final Instant expiresAt;
    private final String samlSessionIndex;
    private boolean active;

    public AuthenticatedSession(String sessionId, String userId, String issuer,
                                Map<String, List<String>> userAttributes,
                                Instant expiresAt, String samlSessionIndex) {
        this.sessionId = sessionId;
        this.userId = userId;
        this.issuer = issuer;
        this.userAttributes = Collections.unmodifiableMap(new LinkedHashMap<>(userAttributes));
        this.createdAt = Instant.now();
        this.expiresAt = expiresAt;
        this.samlSessionIndex = samlSessionIndex;
        this.active = true;
    }

    public String getSessionId() { return sessionId; }
    public String getUserId() { return userId; }
    public String getIssuer() { return issuer; }
    public Map<String, List<String>> getUserAttributes() { return userAttributes; }
    public Instant getCreatedAt() { return createdAt; }
    public Instant getExpiresAt() { return expiresAt; }
    public String getSamlSessionIndex() { return samlSessionIndex; }
    public boolean isActive() { return active; }

    public void invalidate() { this.active = false; }

    public boolean isExpired() {
        return expiresAt != null && Instant.now().isAfter(expiresAt);
    }

    public boolean isValid() {
        return active && !isExpired();
    }

    public String getAttribute(String name) {
        List<String> values = userAttributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    @Override
    public String toString() {
        return "AuthenticatedSession{sessionId='" + sessionId + "', userId='" + userId +
                "', issuer='" + issuer + "', active=" + active +
                ", expiresAt=" + expiresAt + ", attributes=" + userAttributes.keySet() + "}";
    }
}

// --- SessionManager ---
class SessionManager {
    private final ConcurrentHashMap<String, AuthenticatedSession> sessions = new ConcurrentHashMap<>();
    private final ConcurrentHashMap<String, String> samlSessionIndex = new ConcurrentHashMap<>();

    public AuthenticatedSession createSession(SAMLResponse samlResponse) throws SAMLException {
        if (!samlResponse.isSuccess()) {
            throw new SAMLException("SAML response status is not Success: " + samlResponse.getStatusCode() +
                    (samlResponse.getStatusMessage() != null ? " - " + samlResponse.getStatusMessage() : ""));
        }

        SAMLAssertion assertion = samlResponse.getFirstAssertion();
        if (assertion == null) {
            throw new SAMLException("No assertions found in SAML response");
        }

        if (!assertion.isTimeValid()) {
            throw new SAMLException("SAML assertion is not within valid time window. " +
                    "NotBefore: " + assertion.getNotBefore() + ", NotOnOrAfter: " + assertion.getNotOnOrAfter());
        }

        String userId = assertion.getSubject();
        if (userId == null || userId.trim().isEmpty()) {
            throw new SAMLException("No subject/user identifier found in SAML assertion");
        }

        Map<String, List<String>> userAttributes = new LinkedHashMap<>();
        for (Map.Entry<String, SAMLAttribute> entry : assertion.getAttributes().entrySet()) {
            userAttributes.put(entry.getKey(), entry.getValue().getValues());
        }

        Instant expiresAt = assertion.getNotOnOrAfter();
        if (expiresAt == null) {
            // Default session duration: 1 hour
            expiresAt = Instant.now().plusSeconds(3600);
        }

        String sessionId = UUID.randomUUID().toString();
        AuthenticatedSession session = new AuthenticatedSession(
                sessionId, userId, assertion.getIssuer(),
                userAttributes, expiresAt, assertion.getSessionIndex());

        sessions.put(sessionId, session);

        if (assertion.getSessionIndex() != null) {
            samlSessionIndex.put(assertion.getSessionIndex(), sessionId);
        }

        return session;
    }

    public AuthenticatedSession getSession(String sessionId) {
        if (sessionId == null) return null;
        AuthenticatedSession session = sessions.get(sessionId);
        if (session != null && !session.isValid()) {
            invalidateSession(sessionId);
            return null;
        }
        return session;
    }

    public void invalidateSession(String sessionId) {
        AuthenticatedSession session = sessions.remove(sessionId);
        if (session != null) {
            session.invalidate();
            if (session.getSamlSessionIndex() != null) {
                samlSessionIndex.remove(session.getSamlSessionIndex());
            }
        }
    }

    public void invalidateBySamlSessionIndex(String samlIndex) {
        if (samlIndex == null) return;
        String sessionId = samlSessionIndex.get(samlIndex);
        if (sessionId != null) {
            invalidateSession(sessionId);
        }
    }

    public int getActiveSessionCount() {
        cleanExpiredSessions();
        return sessions.size();
    }

    public void cleanExpiredSessions() {
        sessions.entrySet().removeIf(entry -> !entry.getValue().isValid());
    }
}

// --- SAMLProcessor (main orchestrator) ---
class SAMLProcessor {
    private final SAMLResponseParser parser;
    private final SessionManager sessionManager;
    private String expectedAudience;
    private String expectedDestination;
    private Set<String> trustedIssuers;

    public SAMLProcessor() {
        this.parser = new SAMLResponseParser();
        this.sessionManager = new SessionManager();
        this.trustedIssuers = new HashSet<>();
    }

    public void setExpectedAudience(String audience) { this.expectedAudience = audience; }
    public void setExpectedDestination(String destination) { this.expectedDestination = destination; }
    public void addTrustedIssuer(String issuer) { this.trustedIssuers.add(issuer); }

    public SessionManager getSessionManager() { return sessionManager; }

    public AuthenticatedSession processSamlResponse(String samlXml) throws SAMLException {
        SAMLResponse response = parser.parse(samlXml);
        return processAndValidate(response);
    }

    public AuthenticatedSession processBase64SamlResponse(String base64Response) throws SAMLException {
        SAMLResponse response = parser.parseBase64(base64Response);
        return processAndValidate(response);
    }

    private AuthenticatedSession processAndValidate(SAMLResponse response) throws SAMLException {
        validateResponse(response);
        return sessionManager.createSession(response);
    }

    private void validateResponse(SAMLResponse response) throws SAMLException {
        if (!response.isSuccess()) {
            throw new SAMLException("SAML authentication failed. Status: " + response.getStatusCode());
        }

        // Validate destination
        if (expectedDestination != null && response.getDestination() != null) {
            if (!expectedDestination.equals(response.getDestination())) {
                throw new SAMLException("SAML response destination mismatch. Expected: " +
                        expectedDestination + ", Got: " + response.getDestination());
            }
        }

        // Validate issuer
        if (!trustedIssuers.isEmpty()) {
            String issuer = response.getIssuer();
            if (issuer == null || !trustedIssuers.contains(issuer)) {
                throw new SAMLException("SAML response issuer is not trusted: " + issuer);
            }
        }

        // Validate assertions
        if (response.getAssertions().isEmpty()) {
            throw new SAMLException("No assertions found in SAML response");
        }

        for (SAMLAssertion assertion : response.getAssertions()) {
            validateAssertion(assertion);
        }
    }

    private void validateAssertion(SAMLAssertion assertion) throws SAMLException {
        // Time validation
        if (!assertion.isTimeValid()) {
            throw new SAMLException("Assertion time conditions not met");
        }

        // Audience restriction validation
        if (expectedAudience != null && !assertion.getAudienceRestrictions().isEmpty()) {
            if (!assertion.getAudienceRestrictions().contains(expectedAudience)) {
                throw new SAMLException("Audience restriction not satisfied. Expected: " +
                        expectedAudience + ", Got: " + assertion.getAudienceRestrictions());
            }
        }

        // Subject validation
        if (assertion.getSubject() == null || assertion.getSubject().trim().isEmpty()) {
            throw new SAMLException("Assertion subject (NameID) is missing");
        }

        // Issuer trust validation
        if (!trustedIssuers.isEmpty()) {
            String assertionIssuer = assertion.getIssuer();
            if (assertionIssuer == null || !trustedIssuers.contains(assertionIssuer)) {
                throw new SAMLException("Assertion issuer is not trusted: " + assertionIssuer);
            }
        }
    }
}

